import pika
import json
import time
import sys
from datetime import datetime
import threading


class RabbitMQPublisher:
    def __init__(self, host='localhost', port=5672, queue_name='task_queue'):
        self.host = host
        self.port = port
        self.queue_name = queue_name
        self.connection = None
        self.channel = None
        
    def connect(self):
        self.connection = pika.BlockingConnection(
            pika.ConnectionParameters(host=self.host, port=self.port)
        )
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue=self.queue_name, durable=True)
        
    def publish_message(self, message):
        if not self.connection or self.connection.is_closed:
            self.connect()
            
        message_body = json.dumps({
            'task': message,
            'timestamp': datetime.now().isoformat(),
            'status': 'pending'
        })
        
        self.channel.basic_publish(
            exchange='',
            routing_key=self.queue_name,
            body=message_body,
            properties=pika.BasicProperties(
                delivery_mode=2,  # make message persistent
            )
        )
        print(f"[Publisher] Sent: {message}")
        
    def publish_multiple(self, messages):
        for message in messages:
            self.publish_message(message)
            
    def close(self):
        if self.connection and not self.connection.is_closed:
            self.connection.close()


class RabbitMQConsumer:
    def __init__(self, host='localhost', port=5672, queue_name='task_queue'):
        self.host = host
        self.port = port
        self.queue_name = queue_name
        self.connection = None
        self.channel = None
        
    def connect(self):
        self.connection = pika.BlockingConnection(
            pika.ConnectionParameters(host=self.host, port=self.port)
        )
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue=self.queue_name, durable=True)
        self.channel.basic_qos(prefetch_count=1)
        
    def callback(self, ch, method, properties, body):
        try:
            message = json.loads(body)
            print(f"[Consumer] Received: {message['task']}")
            print(f"[Consumer] Timestamp: {message['timestamp']}")
            
            # Simulate task processing
            processing_time = len(message['task'].split('.')) 
            print(f"[Consumer] Processing task (will take {processing_time} seconds)...")
            time.sleep(processing_time)
            
            print(f"[Consumer] Task completed: {message['task']}")
            ch.basic_ack(delivery_tag=method.delivery_tag)
            
        except Exception as e:
            print(f"[Consumer] Error processing message: {e}")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
            
    def start_consuming(self):
        if not self.connection or self.connection.is_closed:
            self.connect()
            
        print(f"[Consumer] Waiting for messages in queue '{self.queue_name}'...")
        print("[Consumer] Press CTRL+C to exit")
        
        self.channel.basic_consume(
            queue=self.queue_name,
            on_message_callback=self.callback
        )
        
        try:
            self.channel.start_consuming()
        except KeyboardInterrupt:
            print("\n[Consumer] Stopping consumer...")
            self.channel.stop_consuming()
            
    def close(self):
        if self.connection and not self.connection.is_closed:
            self.connection.close()


class TaskProcessor:
    def __init__(self, host='localhost', port=5672, queue_name='task_queue'):
        self.publisher = RabbitMQPublisher(host, port, queue_name)
        self.consumer = RabbitMQConsumer(host, port, queue_name)
        
    def run_publisher(self, tasks):
        try:
            self.publisher.connect()
            self.publisher.publish_multiple(tasks)
        finally:
            self.publisher.close()
            
    def run_consumer(self):
        try:
            self.consumer.connect()
            self.consumer.start_consuming()
        except KeyboardInterrupt:
            pass
        finally:
            self.consumer.close()


def main():
    if len(sys.argv) < 2:
        print("Usage:")
        print("  Publisher mode: python app.py publish [task1] [task2] ...")
        print("  Consumer mode: python app.py consume")
        sys.exit(1)
        
    mode = sys.argv[1]
    
    if mode == 'publish':
        if len(sys.argv) < 3:
            tasks = [
                "Process user registration",
                "Send welcome email",
                "Generate monthly report",
                "Backup database",
                "Update analytics data"
            ]
        else:
            tasks = sys.argv[2:]
            
        processor = TaskProcessor()
        print("[Publisher] Publishing tasks...")
        processor.run_publisher(tasks)
        print(f"[Publisher] Published {len(tasks)} tasks successfully")
        
    elif mode == 'consume':
        processor = TaskProcessor()
        processor.run_consumer()
        
    else:
        print(f"Unknown mode: {mode}")
        print("Use 'publish' or 'consume'")
        sys.exit(1)


if __name__ == '__main__':
    main()